const body = $input.first().json.body || {};
if (body.confirm !== true) {
  throw new Error('Se requiere { "confirm": true } en el body para ejecutar la limpieza.');
}
return { json: { confirmed: true } };

const row = $input.first().json;
const total = Object.values(row).reduce((a, b) => a + b, 0);
return {
  json: {
    success: true,
    message: `Limpieza completada. ${total} registros eliminados en total.`,
    deleted: row,
    next_step: 'Ejecutar POST /ia4sdlc-init-content-status con {"mode":"full"} para reinicializar.'
  }
};
